// NODO: Parse & Clean - Gemini Prices (Single Document Edition)
// VERSIONE: 1.3 - Restituisce un unico documento con l'array inserito dentro

const item = $input.first().json;
let rawText = "";

if (item.candidates && Array.isArray(item.candidates) && item.candidates.length > 0) {
    rawText = item.candidates[0].content?.parts?.[0]?.text || "";
} else if (item.content?.parts?.[0]?.text) {
    rawText = item.content.parts[0].text;
} else if (item.parts?.[0]?.text) {
    rawText = item.parts[0].text;
} else {
    rawText = typeof item === 'string' ? item : (item.text || "");
}

if (!rawText || rawText.trim() === "") {
    throw new Error("Errore Parser: Impossibile individuare il testo generato da Gemini.");
}

let cleaned = rawText.replace(/^```(?:json)?\s*/i, "").replace(/\s*```$/, "").trim();

let parsedArray = [];
try {
    parsedArray = JSON.parse(cleaned);
} catch (e) {
    throw new Error(`Errore Parser: Impossibile convertire il testo in JSON. Errore: ${e.message}`);
}

if (!Array.isArray(parsedArray)) {
    throw new Error("Errore Parser: Il payload convertito non è un array.");
}

// RESTITUISCE UN UNICO ITEM N8N (Un solo documento MongoDB)
return [{
    json: {
        updated_at: new Date().toISOString(),
        listino_prezzi: parsedArray // L'array di 9 modelli è qui dentro
    }
}];
